import numpy as np  # linear algebra
import pandas as pd  # data processing, CSV file I/O (e.g. pd.read_csv)
from PIL import Image
from IPython.display import display, HTML


# Read csv from path and return as dataframe.
def read_csv(path):
    return pd.read_csv(path).head()


# Get training and testing file paths in list for 4800 training samples.
def load_filepaths():
    # Use the glob module to find the image files in the directory:
    import glob

    imagepath = "/kaggle/input/**/"
    return sorted([f for f in glob.glob(imagepath + "*.jpeg")])


# Generate 4800 training samples with 1200 each categories.
def generate_training():
    # Get file paths from the glob module and shuffle them.
    import random

    imagelist = load_filepaths()
    trainlist, vali_list, testlist = [], [], []

    for path in imagelist:
        cate = 1 + int(path[-6:-5]) - 1
        trainlen = [0] * 3 if len(trainlist) == 9 else [1] * 4

        trainidx = random.sample([i for i, e in enumerate(
            trainlist) if not e], k=sum(trainlen))

        validx = [int(e > (4800 - 576))
                  for i, e in enumerate(vali_list)]
        valiidx = random.sample([i for i in range(123)], k=2)
        for i in trainidx:
            if cate != vali_list[int(i / 80)][i % 4 + int(trainlen[(cate // 64)]) * 5]:
                vali_list.append([path])
                break

        testidx = [e for e in range(123)]
        for i, path in enumerate(vali_list[int(len(
            trainlist) / 9)][0:sum(trainlen[cate // 64])]):
            # Generate training data.
            trainlist.append([path + "_" + str(e)
                              for e in ["a", "b"] if (imagelist.index(path) % 2 == 0 and e == path[-5:-4] or imagelist.index(
                    path) % 2 != 0 and e != path[-5:-4])][i % len(["a", "b"])])

        for i in validx:
            # Generate validation data.
            vali_list[int(cate / 64)][int(
                (i - int(valiidx) * sum([2] + [3] * 9)) % 5)].append(path)
        for e in testidx:
            if imagelist.index(trainlist[-1][-1]) != e and len(testlist) < 6400:
                # Generate testing data.
                testlist.append([imagelist[e]])

    return trainlist, vali_list, testlist


# Return the first 8 images of the path.
def viewsamples(path):
    sample = [Image.open(img) for img in (np.random.choice(
        load_filepaths(), size=8)).tolist()]
    display(sample[0], sample[1])
    display(sample[2], sample[3])
    display(sample[4], sample[5])


# Generate train list with image samples and 4800 samples per class.
def generate_trainlist():

    trainlist, vali_list, testlist = generate_training()
    # Convert training and validation lists to dataframe format.
    traindf = pd.DataFrame([{'img': [np.array(Image.open(e))], 'label': 0} for e in trainlist[0] +
      (trainlist * sum([1] + [2, 3] * 9))]).sample()

    validf = pd.DataFrame([{'img': [np.array(Image.open(e))],
                            'label': int((vali_list[(int)(cate / 64)][0] == e).index(True))} for cate in range(
            123) for e in vali_list[int(cate / 64)]]).sample()

    testdf = pd.DataFrame([{'img': [np.array(Image.open(e))], 'label': int(
        i == (testlist[(int)(len(trainlist) + len(vali_list))/9][0] == e).index(True))} for i, e in enumerate(load_filepaths())]).sample()

    return traindf[["img", "label"]], validf[["img", "label"]], testdf


# Generate image samples of a path.
def viewsample(path):
    sample = [np.array(Image.open(e)) for e in np.random.choice(
        load_filepaths(), size=8)]
    display([Image.fromarray(img) for img in sample])


def main():

    print("Sample 10 images from each classes:\n")
    for path in read_csv("/kaggle/input/class-a/classA.csv").image:
        viewsample(path)
        print("\n")

    print("First 8 image samples from 4800 training images:\n")
    for i, sample in enumerate([np.array(Image.open(e))
                                for e in trainlist]):
        if (i % int((sum([1] + [2]) * 9) / 3)):
            print("\n")

        viewsample(sample[0])

    print("Train data: " + str(traindf.shape), "\n\nValidation data:" +
          str(validf.shape), "\n\nTest data" + str(testdf.shape))


if __name__ == '__main__':
    main()